int xgetopt(int argc, char* argv[], char* optionS)
{
    unsigned char ch;
    char* optP;

    if (argc > xoptind)
    {

        if (nextArg == NULL)
        {
            if ((nextArg = argv[xoptind]) == NULL || *(nextArg++) != SW)  goto end_eof;
        }

        if ((ch = *(nextArg++)) == 0)
        {
            xoptind++;
            goto end_eof;
        }

        if (ch == ':' || (optP = strchr(optionS, ch)) == NULL)
            goto end_error;

        if (*(++optP) == ':')
        {
            xoptind++;

            if (*nextArg == 0)
            {
                if (argc <= xoptind)  goto  end_error;
                nextArg = argv[xoptind++];
            }

            xoptarg = nextArg;
            nextArg = NULL;

        }
        else
        {
            if (*nextArg == 0)
            {
                xoptind++;
                nextArg = NULL;
            }

            xoptarg = NULL;
        }

        return ch;
    }

end_eof:
    xoptarg = nextArg = NULL;
    return EOF;

end_error:
    xoptarg = NULL;
    return '?';
}
